import outlines
from outlines.prompts import register_filter, unregister_filter, prompt

@prompt
def direct_prompt(text):
    '''{{ text }}'''

print(repr(direct_prompt('hello')))

@prompt(filters={'reverse': lambda s: s[::-1]})
def reverse_prompt(text):
    '''{{ text | reverse }}'''

print(repr(reverse_prompt('hello')))

register_filter('shout', lambda s: s.upper() + '!!!')

@prompt
def shout_prompt(text):
    '''{{ text | shout }}'''

print(repr(shout_prompt('hi')))

unregister_filter('shout')
